\\draw[->] (0,0) -- (6,0) node[right] {Time (s)};
\\draw[->] (0,0) -- (0,6) node[above] {Amplitude};
\\draw[blue, thick] plot[domain=0:5.5, samples=100] (\\x,{2*sin(360*\\x*6/100)});
\\draw[dashed] (0,5) -- (6,5) node[above] {Peak value: 5 V};
\\draw (0,5) node[left] {5};
\\draw (5.5,0) node[below] {1 second: Frequency: 6 Hz};
\\draw (0,0) node[below] {a. A sine wave in the time domain (peak value: 5 V, frequency: 6 Hz)};
\\end{tikzpicture}
\\end{center}

\\begin{center}
