\\quad
\\begin{tikzpicture}[scale=0.8, every node/.style={scale=0.8}]
\\node[draw, circle, minimum size=1cm] (source) at (0,0) {Source};
\\node[draw, circle, minimum size=1cm] (g1) at (-2,-2) {G1};
